class Solution {
    public long maximumOr(int[] nums, int k) {
        PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);
        for (int num : nums) {
            pq.offer(num);
        }
        while (k-- > 0) {
            int max = pq.poll();
            pq.offer(max * 2);
        }
        long res = 0;
        while (!pq.isEmpty()) {
            res |= pq.poll();
        }
        return res;
    }
}
